import java.util.*;

public class Memoization {

    // ── Fibonacci with memoization ──────────────────────────────────────────
    private static Map<Integer, Long> fibMemo = new HashMap<>();

    public static long fib(int n) {
        if (n <= 1) return n;
        if (fibMemo.containsKey(n)) return fibMemo.get(n);
        long result = fib(n - 1) + fib(n - 2);
        fibMemo.put(n, result);
        return result;
    }

    // ── Coin Change — minimum coins to make amount ──────────────────────────
    private static int[] coinMemo;

    public static int coinChange(int[] coins, int amount) {
        coinMemo = new int[amount + 1];
        Arrays.fill(coinMemo, -1);
        int result = coinHelper(coins, amount);
        return result == Integer.MAX_VALUE ? -1 : result;
    }

    private static int coinHelper(int[] coins, int rem) {
        if (rem == 0) return 0;
        if (rem < 0)  return Integer.MAX_VALUE;
        if (coinMemo[rem] != -1) return coinMemo[rem]; // cached

        int best = Integer.MAX_VALUE;
        for (int coin : coins) {
            int sub = coinHelper(coins, rem - coin);
            if (sub != Integer.MAX_VALUE) best = Math.min(best, sub + 1);
        }
        coinMemo[rem] = best;
        return best;
    }

    // ── Longest Common Subsequence ──────────────────────────────────────────
    private static int[][] lcsMemo;

    public static int lcs(String a, String b) {
        lcsMemo = new int[a.length() + 1][b.length() + 1];
        for (int[] row : lcsMemo) Arrays.fill(row, -1);
        return lcsHelper(a, b, a.length(), b.length());
    }

    private static int lcsHelper(String a, String b, int i, int j) {
        if (i == 0 || j == 0) return 0;
        if (lcsMemo[i][j] != -1) return lcsMemo[i][j];
        int result = (a.charAt(i - 1) == b.charAt(j - 1))
                ? 1 + lcsHelper(a, b, i - 1, j - 1)
                : Math.max(lcsHelper(a, b, i - 1, j), lcsHelper(a, b, i, j - 1));
        lcsMemo[i][j] = result;
        return result;
    }
}

public class Tabulation {

    // ── Fibonacci — O(n) time, O(1) space ──────────────────────────────────
    public static long fib(int n) {
        if (n <= 1) return n;
        long prev2 = 0, prev1 = 1;
        for (int i = 2; i <= n; i++) {
            long curr = prev1 + prev2;
            prev2 = prev1;
            prev1 = curr;
        }
        return prev1;
    }

    // ── 0/1 Knapsack — O(n*W) time, O(W) space ─────────────────────────────
    public static int knapsack(int[] weights, int[] values, int W) {
        int n  = weights.length;
        int[] dp = new int[W + 1]; // dp[w] = max value with capacity w

        for (int i = 0; i < n; i++) {
            // iterate backwards to prevent using item i twice
            for (int w = W; w >= weights[i]; w--) {
                dp[w] = Math.max(dp[w], dp[w - weights[i]] + values[i]);
            }
        }
        return dp[W];
    }

    // ── Longest Increasing Subsequence — O(n²) DP ──────────────────────────
    public static int lis(int[] nums) {
        int n   = nums.length;
        int[] dp = new int[n]; // dp[i] = LIS ending at index i
        Arrays.fill(dp, 1);   // every element alone is LIS of length 1

        int max = 1;
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[j] < nums[i]) {
                    dp[i] = Math.max(dp[i], dp[j] + 1);
                }
            }
            max = Math.max(max, dp[i]);
        }
        return max;
    }

    // ── Edit Distance (Levenshtein) — O(m*n) ───────────────────────────────
    public static int editDistance(String a, String b) {
        int m = a.length(), n = b.length();
        int[] prev = new int[n + 1];
        for (int j = 0; j <= n; j++) prev[j] = j; // base case: transform empty→b

        for (int i = 1; i <= m; i++) {
            int[] curr = new int[n + 1];
            curr[0] = i; // base case: transform a[0..i]→empty
            for (int j = 1; j <= n; j++) {
                if (a.charAt(i - 1) == b.charAt(j - 1)) curr[j] = prev[j - 1];
                else curr[j] = 1 + Math.min(prev[j - 1],    // replace
                                   Math.min(prev[j],          // delete
                                            curr[j - 1]));    // insert
            }
            prev = curr;
        }
        return prev[n];
    }
}

public class Knapsack {

    // ── Classic 0/1 Knapsack ────────────────────────────────────────────────
    public static int knapsack01(int[] weights, int[] values, int W) {
        int n  = weights.length;
        int[] dp = new int[W + 1];

        for (int i = 0; i < n; i++) {
            for (int w = W; w >= weights[i]; w--) { // backwards!
                dp[w] = Math.max(dp[w], dp[w - weights[i]] + values[i]);
            }
        }
        return dp[W];
    }

    // ── Subset Sum — can we reach target? ──────────────────────────────────
    public static boolean subsetSum(int[] nums, int target) {
        boolean[] dp = new boolean[target + 1];
        dp[0] = true; // empty subset sums to 0

        for (int num : nums) {
            for (int t = target; t >= num; t--) {
                dp[t] = dp[t] || dp[t - num];
            }
        }
        return dp[target];
    }

    // ── Partition Equal Subset Sum ──────────────────────────────────────────
    public static boolean canPartition(int[] nums) {
        int total = 0;
        for (int n : nums) total += n;
        if (total % 2 != 0) return false;
        return subsetSum(nums, total / 2);
    }

    // ── Coin Change (unbounded knapsack variant) ────────────────────────────
    public static int coinChange(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1); // sentinel: larger than any valid answer
        dp[0] = 0;

        for (int coin : coins) {
            for (int a = coin; a <= amount; a++) { // forwards = unbounded
                dp[a] = Math.min(dp[a], dp[a - coin] + 1);
            }
        }
        return dp[amount] > amount ? -1 : dp[amount];
    }
}
